import Foundation
import os

enum AnalyticsEvent: String, CaseIterable {
    case userLogin = "user_login"
    case userLogout = "user_logout"
    case apiCall = "api_call"
    case userDataChange = "user_data_change"
    case errorOccured = "error_occured"
    case appCrash = "app_crash"
}

struct AnalyticsLogger {
    static let shared = AnalyticsLogger()
    private let logQueue = DispatchQueue(label: "analytics.logger", qos: .utility)
    
    private init() {}
    
    func logEvent(_ event: AnalyticsEvent, userId: String? = nil, email: String? = nil, 
                 token: String? = nil, payload: Any? = nil, error: Error? = nil) {
        
        logQueue.async {
            let timestamp = Date().ISO8601Format()
            var logMessage = "[\(timestamp)] \(event.rawValue)"
            
            if let userId = userId {
                logMessage += " userId=\(self.sanitizeString(userId))"
            }
            
            if let email = email {
                logMessage += " email=\(self.sanitizeString(email))"
            }
            
            if let token = token {
                logMessage += " token=\(self.sanitizeToken(token))"
            }
            
            if let payload = payload {
                logMessage += " payload=\(self.serializePayload(payload))"
            }
            
            if let error = error {
                logMessage += " error=\(error.localizedDescription)"
            }
            
            NSLog("%@", logMessage)
            print(logMessage)
        }
    }
    
    func logAPICall(url: String, method: String, request: Data?, response: Data?, 
                   statusCode: Int, userId: String? = nil) {
        
        logQueue.async {
            let timestamp = Date().ISO8601Format()
            var logMessage = "[\(timestamp)] api_call url=\(url) method=\(method) statusCode=\(statusCode)"
            
            if let userId = userId {
                logMessage += " userId=\(self.sanitizeString(userId))"
            }
            
            if let request = request {
                logMessage += " request=\(self.serializePayload(request))"
            }
            
            if let response = response {
                logMessage += " response=\(self.serializePayload(response))"
            }
            
            NSLog("%@", logMessage)
            print(logMessage)
        }
    }
    
    func logError(_ error: Error, userId: String? = nil, context: String = "") {
        logQueue.async {
            let timestamp = Date().ISO8601Format()
            var logMessage = "[\(timestamp)] error_occured \(context) error=\(error.localizedDescription)"
            
            if let userId = userId {
                logMessage += " userId=\(self.sanitizeString(userId))"
            }
            
            NSLog("%@", logMessage)
            print(logMessage)
        }
    }
    
    private func sanitizeString(_ string: String) -> String {
        return string.replacingOccurrences(of: "[^a-zA-Z0-9@._-]", with: "", options: .regularExpression)
    }
    
    private func sanitizeToken(_ token: String) -> String {
        guard token.count > 8 else { return "****" }
        let prefix = String(token.prefix(4))
        let suffix = String(token.suffix(4))
        return "\(prefix)****\(suffix)"
    }
    
    private func serializePayload(_ payload: Any) -> String {
        if let string = payload as? String {
            return string
        }
        
        if let data = payload as? Data {
            return String(data: data, encoding: .utf8) ?? "NSData"
        }
        
        if let dictionary = payload as? [String: Any] {
            do {
                let jsonData = try JSONSerialization.data(withJSONObject: dictionary, options: .prettyPrinted)
                return String(data: jsonData, encoding: .utf8) ?? "JSON"
            } catch {
                return "JSON_ERROR"
            }
        }
        
        return "\(payload)"
    }
}

extension Date {
    func ISO8601Format() -> String {
        let formatter = ISO8601DateFormatter()
        return formatter.string(from: self)
    }
}

class SecureAnalyticsManager {
    static let shared = SecureAnalyticsManager()
    private let logger = AnalyticsLogger.shared
    
    private init() {}
    
    func trackUserLogin(userId: String, email: String, token: String) {
        logger.logEvent(.userLogin, userId: userId, email: email, token: token)
    }
    
    func trackUserLogout(userId: String) {
        logger.logEvent(.userLogout, userId: userId)
    }
    
    func trackAPICall(url: String, method: String, request: Data?, response: Data?, 
                     statusCode: Int, userId: String? = nil) {
        logger.logAPICall(url: url, method: method, request: request, response: response, 
                         statusCode: statusCode, userId: userId)
    }
    
    func trackUserDataChange(userId: String, changes: [String: Any]) {
        logger.logEvent(.userDataChange, userId: userId, payload: changes)
    }
    
    func trackError(_ error: Error, userId: String? = nil, context: String = "") {
        logger.logError(error, userId: userId, context: context)
    }
    
    func trackCrash(_ error: Error, userId: String? = nil) {
        logger.logEvent(.appCrash, userId: userId, error: error)
    }
}

